// Level order (BFS)
var q = new Queue<TreeNode>(); q.Enqueue(root);
while (q.Count > 0) {
    int sz = q.Count;                       // freeze this level's size
    for (int i = 0; i < sz; i++) {
        var node = q.Dequeue(); Visit(node);
        if (node.left != null) q.Enqueue(node.left);
        if (node.right != null) q.Enqueue(node.right);
    }
}

