private int LowerBound(int[] a, int t) {
    int lo = 0, hi = a.Length;                    // half-open [lo, hi)
    while (lo < hi) { int mid = lo + (hi - lo) / 2; if (a[mid] < t) lo = mid + 1; else hi = mid; }
