public TreeNode LowestCommonAncestor(TreeNode root, TreeNode p, TreeNode q) {
    var cur = root;
    while (cur != null) {
        if (p.val < cur.val && q.val < cur.val) cur = cur.left;
        else if (p.val > cur.val && q.val > cur.val) cur = cur.right;
        else return cur;
    }
    return null;
}
