// max — one pass can't satisfy both directions.
public int Candy(int[] ratings) {
    int n = ratings.Length;
    var candy = new int[n];
    Array.Fill(candy, 1);
    for (int i = 1; i < n; i++)
        if (ratings[i] > ratings[i - 1]) candy[i] = candy[i - 1] + 1;
    for (int i = n - 2; i >= 0; i--)
        if (ratings[i] > ratings[i + 1]) candy[i] = Math.Max(candy[i], candy[i + 1] + 1);
    return candy.Sum();
}
