// ways(n) = ways(n-1) + ways(n-2) — Fibonacci, with two rolling variables.
public int ClimbStairs(int n) {
    int a = 1, b = 1;
    for (int i = 2; i <= n; i++) { int c = a + b; a = b; b = c; }
    return b;
}
