// Count combinations (not permutations): loop coins OUTER, amount inner.
public int Change(int amount, int[] coins) {
    var dp = new int[amount + 1];
    dp[0] = 1;
    foreach (int c in coins)
        for (int a = c; a <= amount; a++)
            dp[a] += dp[a - c];
    return dp[amount];
}
```
**Complexity:** O(amount · coins).

